import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; public class PasswordHasher { public static void main(String[] args) { BCryptPasswordEncoder encoder = new BCryptPasswordEncoder(); System.out.println("passAlice: " + encoder.encode("passAlice")); System.out.println("passBob: " + encoder.encode("passBob")); System.out.println("passCarol: " + encoder.encode("passCarol")); System.out.println("passDavid: " + encoder.encode("passDavid")); System.out.println("passEve: " + encoder.encode("passEve")); } }
